import React, { useState } from "react";
import axios from "axios";
import { motion, AnimatePresence } from "framer-motion";

import districtOptions from "../data/district_options.json";
import commodityOptions from "../data/commodity_options.json";

const CropPriceLookup = () => {
    const [district, setDistrict] = useState("");
    const [commodity, setCommodity] = useState("");
    const [prices, setPrices] = useState(null);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");

    const fetchPrices = async () => {
        if (!commodity || !district) {
            setError("Please select both commodity and district.");
            return;
        }

        setLoading(true);
        setError("");

        try {
            const response = await axios.post("http://localhost:5000/api/crops/getPrices", {
                Commodity: commodity,
                District: district,
            });
            setPrices(response.data);
        } catch (err) {
            setError("Failed to fetch price data.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <motion.div 
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5 }}
            className="max-w-lg mx-auto p-8 bg-gradient-to-r from-green-400 via-blue-500 to-purple-600 shadow-2xl rounded-lg border border-gray-300 text-black"
        >
            <motion.h2 
                initial={{ y: -20 }}
                animate={{ y: 0 }}
                transition={{ duration: 0.5 }}
                className="text-4xl font-bold text-center mb-6 drop-shadow-lg"
            >
                🌾 Crop Price Lookup 🌾
            </motion.h2>
            
            <motion.div 
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                transition={{ duration: 0.5, delay: 0.2 }}
                className="space-y-5"
            >
                <motion.select 
                    whileFocus={{ scale: 1.02 }}
                    transition={{ duration: 0.2 }}
                    value={commodity} 
                    onChange={(e) => setCommodity(e.target.value)} 
                    className="w-full p-4 border rounded-lg bg-white text-gray-900 shadow-lg focus:ring-2 focus:ring-yellow-400 hover:shadow-xl transition-all duration-300"
                >
                    <option value="">Select Commodity</option>
                    {commodityOptions.map((item, index) => (
                        <option key={index} value={item}>{item}</option>
                    ))}
                </motion.select>

                <motion.select 
                    whileFocus={{ scale: 1.02 }}
                    transition={{ duration: 0.2 }}
                    value={district} 
                    onChange={(e) => setDistrict(e.target.value)} 
                    className="w-full p-4 border rounded-lg bg-white text-gray-900 shadow-lg focus:ring-2 focus:ring-yellow-400 hover:shadow-xl transition-all duration-300"
                >
                    <option value="">Select District</option>
                    {districtOptions.map((item, index) => (
                        <option key={index} value={item}>{item}</option>
                    ))}
                </motion.select>
            </motion.div>
            
            <motion.button 
                onClick={fetchPrices} 
                whileHover={{ scale: 1.05, boxShadow: "0 8px 16px rgba(0,0,0,0.2)" }}
                whileTap={{ scale: 0.95 }}
                className="w-full mt-6 p-4 bg-yellow-400 text-gray-900 font-bold rounded-lg shadow-xl hover:bg-yellow-500 transition-all duration-300"
            >
                🔍 Get Prices
            </motion.button>
            
            <AnimatePresence>
                {loading && (
                    <motion.p 
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        className="text-center mt-4 text-white animate-pulse"
                    >
                        Loading...
                    </motion.p>
                )}
                {error && (
                    <motion.p 
                        initial={{ opacity: 0, y: -10 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0, y: -10 }}
                        className="text-center mt-4 text-red-200 font-bold"
                    >
                        {error}
                    </motion.p>
                )}
            </AnimatePresence>
            
            <AnimatePresence>
                {prices && (
                    <motion.div 
                        initial={{ opacity: 0, y: 20 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0, y: -20 }}
                        transition={{ duration: 0.3 }}
                        className="mt-8 p-6 bg-white text-gray-900 rounded-lg shadow-2xl"
                    >
                        <motion.h3 
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            transition={{ delay: 0.2 }}
                            className="text-2xl font-semibold text-gray-700 text-center mb-4"
                        >
                            Price Details
                        </motion.h3>
                        <div className="space-y-4">
                            {prices.map((data, index) => (
                                <motion.div
                                    key={index}
                                    initial={{ opacity: 0, x: -20 }}
                                    animate={{ opacity: 1, x: 0 }}
                                    transition={{ delay: index * 0.1 }}
                                    whileHover={{ 
                                        scale: 1.02,
                                        boxShadow: "0 4px 8px rgba(0,0,0,0.1)",
                                        zIndex: 1
                                    }}
                                    className="p-4 bg-gradient-to-r from-yellow-300 to-orange-400 shadow-md rounded-lg border border-gray-300 relative transform transition-all duration-300"
                                >
                                    <p className="font-semibold"><strong>Grade:</strong> {data.Grade}</p>
                                    <p><strong>Min Price:</strong> {data["Min Price"]} ₹</p>
                                    <p><strong>Max Price:</strong> {data["Max Price"]} ₹</p>
                                    <p><strong>Modal Price:</strong> {data["Modal Price"]} ₹</p>
                                </motion.div>
                            ))}
                        </div>
                    </motion.div>
                )}
            </AnimatePresence>
        </motion.div>
    );
};

export default CropPriceLookup;
